// Example: simple circuit breaker
class Breaker {
  constructor(threshold) {
    this.failures = 0;
    this.threshold = threshold;
    this.open = false;
  }
  call(fn) {
    if (this.open) throw new Error('Breaker is open');
    return fn().catch(() => {
      this.failures++;
      if (this.failures > this.threshold) this.open = true;
      throw;
    });
  }
}
```

