class SimpleCB {
  constructor() {
    this.state = 'CLOSED';
    this.failures = 0;
  }
  async call(fn, timeout = 5000) {
    if (this.state === 'OPEN') throw new Error('Circuit open');
    try {
      const t = new Promise(res => setTimeout(res, timeout, 'timeout'));
      const r = await Promise.race([fn(), t]);
      if (r === 'timeout') throw new Error('timeout');
      this.failures = 0;
      return r;
    } catch (e) {
      this.failures++;
      if (this.failures > 2) this.state = 'OPEN';
      throw e;
    }
  }
}
```

